arguments.command:
cd /tmp/sv-a720f275f43b4abcbd4468465419b394/symbols && \
# Try nm to find the function containing those addresses
for addr in 0x2f4b20 0x2f4c84 0x2c1a40; do
  echo "=== $addr ==="
  # Find the function symbol that contains this address
  nm -n libmonosgen-2.0.so.dbg 2>/dev/null | awk -v target="$addr" '
    BEGIN { gsub("0x","",target) }
    /[tT]/ { 
      if (prev_addr != "" && ("0x" prev_addr)+0 <= ("0x" target)+0 && ("0x" $1)+0 > ("0x" target)+0) {
        print prev_addr " " prev_name " (offset +" sprintf("0x%x", ("0x"target) - ("0x"prev_addr)) ")"
      }
      prev_addr=$1; prev_name=$3
    }'
done

