arguments.command:
cd /tmp/sv-a720f275f43b4abcbd4468465419b394/symbols && \
# Use objdump to find which function contains these addresses
for addr in 2f4b20 2f4c84 2c1a40; do
  echo "=== 0x$addr ==="
  # Search nm sorted output for the enclosing function
  nm -n libmonosgen-2.0.so.dbg 2>/dev/null | grep -i " [tTwW] " | awk -v target="0x$addr" '
    BEGIN { targetn = strtonum(target) }
    { 
      cur = strtonum("0x" $1)
      if (cur > targetn && prev != "") { print prev; exit }
      prev = $0
    }'
done

