arguments.command:
cd /tmp/sv-a720f275f43b4abcbd4468465419b394/symbols && \
# These are in the BSS/data section (b = BSS symbol). The addresses 0x2f4b20/0x2f4c84 
# are in the interpreter label table. Let's look at what functions reference them.
# Actually these might be interp dispatch addresses. Let's check if they're in .text
nm -n libmonosgen-2.0.so.dbg 2>/dev/null | awk '
  { addr=strtonum("0x"$1) }
  addr <= 0x2f4b20 && ($2 == "T" || $2 == "t") { last_func=$0 }
  addr > 0x2f4b20 && found==0 { print "0x2f4b20 after: " last_func; found=1 }
' | head -3
